(async () => {
  const REPO = 'juxingmaomi/tavern-html-exporter';
  const VERSION = 'v1.3';
  const URLS = [
    `https://gcore.jsdelivr.net/gh/${REPO}@${VERSION}/index.js`,
    `https://cdn.jsdelivr.net/gh/${REPO}@${VERSION}/index.js`,
  ];

  const state = { repo: REPO, loadedTag: VERSION, urls: URLS, requestedAt: new Date().toISOString() };
  window.__TH_TAVERN_HTML_EXPORTER_LOADER__ = state;

  const popup = (type, message) => {
    const host = window.parent && window.parent !== window ? window.parent : window;
    const toastr = window.toastr || host.toastr;
    if (toastr && typeof toastr[type] === 'function') {
      toastr[type](message);
      return;
    }
    if (type === 'error') host.alert(message);
    else console.log(`[tavern-html-exporter] ${message}`);
  };

  let lastError;
  for (const url of URLS) {
    try {
      await import(url);
      state.loadedUrl = url;
      state.loadedAt = new Date().toISOString();
      popup('success', `聊天记录 HTML 导出器已加载 ${VERSION}`);
      return;
    } catch (error) {
      lastError = error;
      console.warn('[tavern-html-exporter] Load attempt failed.', url, error);
    }
  }

  state.error = String((lastError && lastError.message) || lastError || 'unknown error');
  popup('error', `聊天记录 HTML 导出器 ${VERSION} 加载失败。请确认 GitHub 已发布这个标签，或稍后再试。`);
})();
